Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and cancellation testing:

```csharp
[TestClass]
public class DataFetcherTests
{
    // MSTest natively supports async Task test methods — no special setup needed.

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Use [Timeout] to guard against hangs — value is in milliseconds.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancelsDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        // Handler cancels the token mid-flight
        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK, cts);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler — avoids external mocking libraries.
    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly CancellationTokenSource? _cancelDuring;

        public MockHttpMessageHandler(
            string content,
            HttpStatusCode statusCode,
            CancellationTokenSource? cancelDuring = null)
        {
            _content = content;
            _statusCode = statusCode;
            _cancelDuring = cancelDuring;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            // Simulate mid-request cancellation
            if (_cancelDuring is not null)
            {
                await Task.Yield();
                _cancelDuring.Cancel();
                cancellationToken.ThrowIfCancellationRequested();
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout guard** | `[Timeout(3000)]` fails the test if it hangs |
| **Pre-cancelled token** | `cts.Cancel()` before the call verifies early exit |
| **Mid-flight cancel** | Handler triggers cancel via shared `CancellationTokenSource` |
| **No external deps** | Custom `HttpMessageHandler` replaces the network layer |

Avoid `async void` test methods — MSTest can't observe their exceptions, so they'll silently pass.
